import logging
from logging.handlers import RotatingFileHandler

# Create a logger object
logger = logging.getLogger('my_application')
logger.setLevel(logging.DEBUG)

# Define the log file path and name
log_file_path = 'logs/my_application.log'

# Set up log rotation with a maximum size of 5 MB and keep 3 backup files
handler = RotatingFileHandler(log_file_path, maxBytes=5 * 1024 * 1024, backupCount=3)
logger.addHandler(handler)

# Set the file permissions for the log files to 640 (rw-r-----)
import os
os.chmod(log_file_path, 0o640)

# Example usage of the logger
logger.debug('This is a debug message')
logger.info('This is an info message')
logger.warning('This is a warning message')
logger.error('This is an error message')
logger.critical('This is a critical message')